                        "entity.other.attribute-name.namespace.xml",
                        "entity.other.attribute-name.msbuild",
                        "entity.other.attribute-name.localname.msbuild"
                    ],
                    "settings": { "foreground": "#9CDCFE" }
                },
                {
                    "scope": [
                        "string.quoted.double.xml",
                        "string.quoted.single.xml",
                        "string.quoted.double.msbuild",
                        "string.quoted.single.msbuild"
                    ],
                    "settings": { "foreground": "#CE9178" }
                },
                {
                    "scope": [
                        "entity.name.tag.xml",
                        "entity.name.tag.localname.xml",
                        "entity.name.tag.namespace.xml",
                        "entity.name.tag.msbuild",
                        "entity.name.tag.localname.msbuild"
                    ],
                    "settings": { "foreground": "#569CD6" }
                },
                {
                    "scope": [
                        "variable.other.expression.msbuild",
                        "variable.other.property.msbuild",
                        "variable.other.item.msbuild",
                        "variable.other.metadata.msbuild"
                    ],
                    "settings": { "foreground": "#DCDCAA" }
                }
            ]
        }
    }
