```typescript
import { StrictMode } from "react";
import { createRoot } from "react-dom/client";
import { PublicClientApplication, EventType } from "@azure/msal-browser";
import type { EventMessage, AccountInfo } from "@azure/msal-browser";

import { createBrowserRouter, RouterProvider } from "react-router";
import "./index.css";

import { MsalProvider } from "@azure/msal-react";
import { msalConfig } from "./authConfig";
import { setupApiClient } from "./apiClientSetup";

import App from "./App.tsx";
import { Dashboard } from "./pages/Dashboard.tsx";
import { Milestones } from "./pages/Milestones.tsx";
import { Goals } from "./pages/Goals.tsx";
import { Projects } from "./pages/Projects.tsx";
import { Feedback } from "./pages/Feedback.tsx";

// Create MSAL instance
export const msalInstance = new PublicClientApplication(msalConfig);

// MSAL v5 requires explicit initialization
await msalInstance.initialize();

// Handle redirect promise (required for MSAL v5)
await msalInstance.handleRedirectPromise();

// Default to using the first account if no account is active on page load
if (
  !msalInstance.getActiveAccount() &&
  msalInstance.getAllAccounts().length > 0
) {
  msalInstance.setActiveAccount(msalInstance.getAllAccounts()[0]);
}

// Listen for sign-in event and set active account
// In MSAL v5, LOGIN_SUCCESS payload is now an AccountInfo object
msalInstance.addEventCallback((event: EventMessage) => {
  if (event.eventType === EventType.LOGIN_SUCCESS && event.payload) {
    const account = event.payload as AccountInfo;
    msalInstance.setActiveAccount(account);
  }
});

// Setup authenticated API client
setupApiClient(msalInstance);

// Create router with routes
const router = createBrowserRouter([
  {
    path: "/",
    element: <App />,
    children: [
      {
        path: "dashboard",
        element: <Dashboard />,
      },
    ],
  },
]);

createRoot(document.getElementById("root")!).render(
  <StrictMode>
    <MsalProvider instance={msalInstance}>
      <RouterProvider router={router} />
    </MsalProvider>
  </StrictMode>,
);
```

### App.tsx
```typescript
import { useCallback, useEffect, useMemo, useState } from "react";
import { Outlet } from "react-router";
import {
  AuthenticatedTemplate,
  UnauthenticatedTemplate,
  useMsal,
} from "@azure/msal-react";
import { InteractionRequiredAuthError } from "@azure/msal-browser";
import { NavigationBar } from "./NavigationBar";
import { CopilotKitProvider, CopilotSidebar } from "@copilotkit/react-core/v2";
import type { CopilotKitProviderProps } from "@copilotkit/react-core/v2";
import "@copilotkit/react-core/v2/styles.css";
import "./App.css";
import { NotLoggedIn } from "./pages/NotLoggedIn";
import { apiConfig } from "./authConfig";

/** Acquires and keeps the current MSAL access token in state. Returns null while loading. */
function useMsalToken(): string | null {
  const { instance, accounts } = useMsal();
  const [token, setToken] = useState<string | null>(null);

  const accountId = accounts[0]?.homeAccountId ?? null;

  useEffect(() => {
    const account = accounts[0];
    if (!account) return;
    let cancelled = false;

    instance
      .acquireTokenSilent({ scopes: apiConfig.scopes, account })
      .then((result) => {
        if (!cancelled) setToken(result.accessToken);
      })
      .catch(async (error) => {
        if (error instanceof InteractionRequiredAuthError) {
          const result = await instance.acquireTokenPopup({
            scopes: apiConfig.scopes,
            account,
          });
          if (!cancelled) setToken(result.accessToken);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [instance, accountId]); // eslint-disable-line react-hooks/exhaustive-deps

  return token;
}

function AuthenticatedApp() {
  const token = useMsalToken();

  const headers = useMemo<Record<string, string>>(() => {
    const h: Record<string, string> = {};
    if (token) {
      h.Authorization = `Bearer ${token}`;
    }
    return h;
  }, [token]);

  const onError = useCallback<NonNullable<CopilotKitProviderProps["onError"]>>(
    ({ error }) => {
      console.error("[CopilotKit] runtime error:", error);
    },
    [],
  );

  if (!token) {
    return null;
  }

  return (
    <CopilotKitProvider
      runtimeUrl="/copilotkit"
      headers={headers}
      onError={onError}
    >
      <NavigationBar />
      <Outlet />
      <CopilotSidebar agentId="ProgressAssistant" />
    </CopilotKitProvider>
  );
}

function App() {
  return (
    <div className="App">
      <AuthenticatedTemplate>
        <AuthenticatedApp />
      </AuthenticatedTemplate>
      <UnauthenticatedTemplate>
        <NotLoggedIn />
      </UnauthenticatedTemplate>
    </div>
  );
}

export default App;
```

### NotLoggedIn.tsx
```
import { InteractionStatus } from "@azure/msal-browser";
import { useMsal } from "@azure/msal-react";
import { Loader } from "lucide-react";
import { loginRequest } from "../authConfig";

export function NotLoggedIn() {
  const { instance, inProgress } = useMsal();

  const handleLogin = () => {
    instance.loginPopup(loginRequest).catch((error) => {
      console.error("Login failed:", error);
    });
  };

  return (
    <div style={{ padding: "2rem", textAlign: "center" }}>
      <h2>Welcome to My App</h2>

      <p>Please sign in to access the application.</p>
      <div style={{ marginTop: "1rem" }}>
        {inProgress === InteractionStatus.None ? (
          <button
            onClick={handleLogin}
            style={{
              padding: "0.6rem 1.6rem",
              fontSize: "1rem",
              cursor: "pointer",
            }}
          >
            Sign in
          </button>
        ) : (
          <div className="flex flex-col items-center gap-2 text-gray-500">
            <Loader className="animate-spin w-8 h-8" />
            <p className="text-sm">
              Please complete the sign-in popup to continue.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}
```

