import type { Configuration } from "@azure/msal-browser";
import { LogLevel } from "@azure/msal-browser";
import { env } from "./env";

/**
 * Configuration object to be passed to MSAL instance on creation.
 * For a full list of MSAL.js configuration parameters, visit:
 * https://github.com/AzureAD/microsoft-authentication-library-for-js/blob/dev/lib/msal-browser/docs/configuration.md
 */
export const msalConfig: Configuration = {
  auth: {
    clientId: env.AZURE_CLIENT_ID, // This is the Application (client) ID of your frontend app registration
    authority: `https://login.microsoftonline.com/${env.AZURE_TENANT_ID}`, // This is the Azure AD tenant ID
    // MSAL v5: redirectUri points to the redirect bridge page for COOP support
    redirectUri: `${new URL(env.REDIRECT_URI).origin}/redirect.html`, // Must be registered as a SPA redirectURI on your app registration
    postLogoutRedirectUri: env.POST_LOGOUT_REDIRECT_URI, // Must be registered as a SPA redirectURI on your app registration
  },
  cache: {
    cacheLocation: "localStorage", // This configures where your cache will be stored
    // Note: storeAuthStateInCookie has been removed in MSAL v5
  },
  system: {
    loggerOptions: {
      loggerCallback: (level, message, containsPii) => {
        if (containsPii) {
          return;
        }
        switch (level) {
          case LogLevel.Error:
            console.error(message);
            return;
          case LogLevel.Info:
            console.info(message);
            return;
          case LogLevel.Verbose:
            console.debug(message);
            return;
          case LogLevel.Warning:
            console.warn(message);
            return;
        }
      },
      piiLoggingEnabled: false,
    },
  },
};

/**
 * Scopes you add here will be prompted for user consent during sign-in.
 * By default, MSAL.js will add OIDC scopes (openid, profile, email) to any login request.
 */
export const loginRequest = {
  scopes: ["openid", "profile", "User.Read"],
};

/**
 * API Configuration
 * Scopes for accessing your backend API
 * Replace YOUR_API_CLIENT_ID with the Application (client) ID of your backend API app registration
 */
export const apiConfig = {
  // The URI of your backend API
  uri: env.API_BASE_URL,
  // The scopes required to access your backend API
  // Format: api://YOUR_API_CLIENT_ID/access_as_user
  scopes: [env.API_SCOPE],
};
