<details><summary>UI Repro</summary>

```
import React, { useState } from "react";

interface FormData {
    firstName: string;
    lastName: string;
    password: string;
    email: string;
    age: string;
    city: string;
}

const initialFormData: FormData = {
    firstName: "",
    lastName: "",
    password: "",
    email: "",
    age: "",
    city: "",
};

const fieldLabels: Record<keyof FormData, string> = {
    firstName: "First Name",
    lastName: "Last Name",
    password: "Password",
    email: "Email Address",
    age: "Age",
    city: "City",
};

const validateForm = (data: FormData): Record<string, string> => {
    const newErrors: Record<string, string> = {};

    if (!data.firstName.trim()) {
        newErrors.firstName = "First Name is required";
    }

    if (!data.lastName.trim()) {
        newErrors.lastName = "Last Name is required";
    }

    if (!data.email.trim()) {
        newErrors.email = "Email is required";
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email)) {
        newErrors.email = "Please enter a valid email";
    }

    if (!data.age) {
        newErrors.age = "Age is required";
    } else if (parseInt(data.age) < 18 || parseInt(data.age) > 120) {
        newErrors.age = "Age must be between 18 and 120";
    }

    if (!data.password.trim()) {
        newErrors.password = "Password is required";
    } else if (data.password.length < 6) {
        newErrors.password = "Password must be at least 6 characters";
    }

    if (!data.city.trim()) {
        newErrors.city = "City is required";
    }

    return newErrors;
};

export default function RegistrationForm() {
    const [formData, setFormData] = useState<FormData>(initialFormData);
    const [errors, setErrors] = useState<Record<string, string>>({});
    const [submitted, setSubmitted] = useState(false);

    const handleChange = (field: keyof FormData, value: string) => {
        setFormData((prev) => ({ ...prev, [field]: value }));
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        setSubmitted(true);
    };

    const handleReset = () => {
        setFormData(initialFormData);
        setErrors({});
        setSubmitted(false);
    };

    if (submitted) {
        return (
            <div className="summary">
                <h2>Registration Complete!</h2>
                <p><strong>First Name:</strong> {formData.firstName}</p>
                <p><strong>Last Name:</strong> {formData.lastName}</p>
                <p><strong>Email:</strong> {formData.email}</p>
                <p><strong>Age:</strong> {formData.age}</p>
                <p><strong>City:</strong> {formData.city}</p>
                <button onClick={handleReset}>Start Over</button>
            </div>
        );
    }

    // 5’ĖÅŌāŻ Form inputs ŌĆö one input per field
    return (
        <form onSubmit={handleSubmit}>
            <h2>User Registration</h2>

            <div className="field">
                <label>{fieldLabels.firstName}</label>
                <input
                    value={formData.firstName}
                    onChange={(e) => handleChange("firstName", e.target.value)}
                />
                {errors.firstName && <span className="error">{errors.firstName}</span>}
            </div>

            <div className="field">
                <label>{fieldLabels.lastName}</label>
                <input
                    value={formData.lastName}
                    onChange={(e) => handleChange("lastName", e.target.value)}
                />
                {errors.lastName && <span className="error">{errors.lastName}</span>}
            </div>

            <div className="field">
                <label>{fieldLabels.email}</label>
                <input
                    type="email"
                    value={formData.email}
                    onChange={(e) => handleChange("email", e.target.value)}
                />
                {errors.email && <span className="error">{errors.email}</span>}
            </div>

            <div className="field">
                <label>{fieldLabels.age}</label>
                <input
                    type="number"
                    value={formData.age}
                    onChange={(e) => handleChange("age", e.target.value)}
                />
                {errors.age && <span className="error">{errors.age}</span>}
            </div>

            <div className="field">
                <label>{fieldLabels.city}</label>
                <input
                    value={formData.city}
                    onChange={(e) => handleChange("city", e.target.value)}
                />
                {errors.city && <span className="error">{errors.city}</span>}
            </div>

            <button type="submit">Register</button>
        </form>
    );
}


